// Evolution API — payload de messages.upsert
const body = $input.item.json.body ?? $input.item.json;
const data = body.data ?? {};

const jid     = data?.key?.remoteJid ?? '';
const numero  = jid.replace('@s.whatsapp.net','').replace('@g.us','');
const from    = numero ? '+' + numero : '';

const msg =
  data?.message?.conversation ??
  data?.message?.extendedTextMessage?.text ??
  data?.message?.imageMessage?.caption ?? '';

const fromMe  = data?.key?.fromMe ?? false;
const isGroup = jid.includes('@g.us');

return [{ json: {
  from,
  numero_raw:   numero,
  mensaje:      msg.trim(),
  profile_name: data?.pushName ?? 'Vendedor',
  ignorar:      fromMe || isGroup || !msg.trim()
}}];

const lookup  = $input.item.json ?? {};
const extraer = $('Extraer mensaje').item.json;

const registrado = lookup.ok === true;
const v = lookup.vendedor ?? {};

return [{ json: {
  chatInput:       extraer.mensaje,
  session_id:      extraer.numero_raw,
  numero_raw:      extraer.numero_raw,
  vendedor_id:     v.id     ?? null,
  vendedor_nombre: v.nombre ?? null,
  region:          v.region ?? '',
  estado:          v.estado ?? '',
  registrado:      registrado
}}];

const output = $input.item.json.output ?? '';
const ctx    = $('Set contexto vendedor').item.json;

// Detectar marcador de registro: [REGISTRO:nombre_completo]
const regMatch = output.match(/\[REGISTRO:([^\]]+)\]/);

// Detectar marcador de tipo de consulta: [CONSULTA:tipo]
const conMatch = output.match(/\[CONSULTA:([^\]]+)\]/);

const requiere_registro  = !!regMatch;
const nombre_registro    = regMatch ? regMatch[1].trim() : null;
const tipo_consulta      = conMatch ? conMatch[1].trim().toLowerCase() : 'otro';

// Limpiar marcadores del texto enviado al vendedor
const respuesta_usuario = output
  .replace(/\[REGISTRO:[^\]]+\]/g, '')
  .replace(/\[CONSULTA:[^\]]+\]/g, '')
  .trim();

return [{ json: {
  respuesta_usuario,
  tipo_consulta,
  requiere_registro,
  nombre_registro,
  vendedor_id:  ctx.vendedor_id,
  numero_raw:   ctx.numero_raw
}}];
